import React, { useState, useEffect } from 'react';
import { Box, Typography, Chip, LinearProgress, Grid, Paper } from '@mui/material';
import { useTheme } from '@mui/material/styles';

const RealTimeMonitor = () => {
  const theme = useTheme();
  const [sensorData, setSensorData] = useState({
    spinalAngle: 15,
    shoulderAlignment: 92,
    headPosition: 88,
    postureStatus: 'Good',
    confidence: 94,
  });

  const [isConnected, setIsConnected] = useState(true);

  useEffect(() => {
    // Simulate real-time data updates
    const interval = setInterval(() => {
      setSensorData(prev => ({
        spinalAngle: Math.max(0, Math.min(45, prev.spinalAngle + (Math.random() - 0.5) * 4)),
        shoulderAlignment: Math.max(70, Math.min(100, prev.shoulderAlignment + (Math.random() - 0.5) * 6)),
        headPosition: Math.max(70, Math.min(100, prev.headPosition + (Math.random() - 0.5) * 5)),
        postureStatus: Math.random() > 0.3 ? 'Good' : Math.random() > 0.5 ? 'Fair' : 'Poor',
        confidence: Math.max(80, Math.min(100, prev.confidence + (Math.random() - 0.5) * 3)),
      }));
    }, 2000);

    return () => clearInterval(interval);
  }, []);

  const getStatusColor = (status) => {
    switch (status) {
      case 'Good': return 'success';
      case 'Fair': return 'warning';
      case 'Poor': return 'error';
      default: return 'default';
    }
  };

  const getProgressColor = (value) => {
    if (value >= 85) return 'success';
    if (value >= 70) return 'warning';
    return 'error';
  };

  const MetricCard = ({ title, value, unit, progress, color }) => (
    <Paper 
      sx={{ 
        p: 2, 
        textAlign: 'center',
        background: theme.palette.mode === 'dark' 
          ? 'linear-gradient(135deg, #2d2d2d 0%, #1e1e1e 100%)'
          : 'linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%)',
        border: `1px solid ${theme.palette.divider}`,
      }}
    >
      <Typography variant="body2" color="text.secondary" gutterBottom>
        {title}
      </Typography>
      <Typography variant="h5" sx={{ fontWeight: 'bold', mb: 1 }}>
        {value}{unit}
      </Typography>
      {progress !== undefined && (
        <LinearProgress
          variant="determinate"
          value={progress}
          color={color}
          sx={{
            height: 6,
            borderRadius: 3,
            backgroundColor: theme.palette.action.hover,
          }}
        />
      )}
    </Paper>
  );

  return (
    <Box sx={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* Connection Status */}
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
        <Chip
          label={isConnected ? 'Sensors Connected' : 'Disconnected'}
          color={isConnected ? 'success' : 'error'}
          variant="outlined"
          size="small"
        />
        <Chip
          label={`Status: ${sensorData.postureStatus}`}
          color={getStatusColor(sensorData.postureStatus)}
          sx={{ fontWeight: 'bold' }}
        />
      </Box>

      {/* Real-time Metrics */}
      <Grid container spacing={2} sx={{ flexGrow: 1 }}>
        <Grid item xs={6} md={3}>
          <MetricCard
            title="Spinal Angle"
            value={sensorData.spinalAngle.toFixed(1)}
            unit="°"
            progress={Math.max(0, 100 - (sensorData.spinalAngle / 45) * 100)}
            color={sensorData.spinalAngle < 20 ? 'success' : sensorData.spinalAngle < 30 ? 'warning' : 'error'}
          />
        </Grid>
        
        <Grid item xs={6} md={3}>
          <MetricCard
            title="Shoulder Alignment"
            value={sensorData.shoulderAlignment.toFixed(0)}
            unit="%"
            progress={sensorData.shoulderAlignment}
            color={getProgressColor(sensorData.shoulderAlignment)}
          />
        </Grid>
        
        <Grid item xs={6} md={3}>
          <MetricCard
            title="Head Position"
            value={sensorData.headPosition.toFixed(0)}
            unit="%"
            progress={sensorData.headPosition}
            color={getProgressColor(sensorData.headPosition)}
          />
        </Grid>
        
        <Grid item xs={6} md={3}>
          <MetricCard
            title="Confidence"
            value={sensorData.confidence.toFixed(0)}
            unit="%"
            progress={sensorData.confidence}
            color="info"
          />
        </Grid>
      </Grid>

      {/* Visual Indicator */}
      <Box sx={{ mt: 2, textAlign: 'center' }}>
        <Box
          sx={{
            width: 60,
            height: 60,
            borderRadius: '50%',
            margin: '0 auto',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            background: `linear-gradient(45deg, ${theme.palette[getStatusColor(sensorData.postureStatus)].main} 30%, ${theme.palette[getStatusColor(sensorData.postureStatus)].light} 90%)`,
            animation: 'pulse 2s infinite',
            '@keyframes pulse': {
              '0%': {
                transform: 'scale(1)',
                opacity: 1,
              },
              '50%': {
                transform: 'scale(1.05)',
                opacity: 0.8,
              },
              '100%': {
                transform: 'scale(1)',
                opacity: 1,
              },
            },
          }}
        >
          <Typography variant="h6" sx={{ color: 'white', fontWeight: 'bold' }}>
            {sensorData.postureStatus[0]}
          </Typography>
        </Box>
        <Typography variant="caption" color="text.secondary" sx={{ mt: 1, display: 'block' }}>
          Live Monitoring Active
        </Typography>
      </Box>
    </Box>
  );
};

export default RealTimeMonitor;
